import { useState } from "react";

export default function DomainPicker({ domains, onPick }) {
  const [query, setQuery] = useState("");

  const colors = ["#3b82f6","#8b5cf6","#ec4899","#f59e0b","#10b981"];

  const filtered = domains.filter(d =>
    d.label.toLowerCase().includes(query.toLowerCase()) ||
    d.id.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <div>
      <div style={{marginBottom:28}}>
        <input
          type="text"
          value={query}
          onChange={e => setQuery(e.target.value)}
          placeholder="Type a domain... e.g. devops, mobile, AI"
          autoFocus
          style={{
            width:"100%",
            padding:"16px 20px",
            fontSize:16,
            borderRadius:14,
            border:"2px solid #334155",
            background:"#1e293b",
            color:"#fff",
            outline:"none",
            boxSizing:"border-box",
            transition:"border 0.2s"
          }}
          onFocus={e => e.target.style.borderColor="#3b82f6"}
          onBlur={e => e.target.style.borderColor="#334155"}
        />
        {query && (
          <p style={{color:"#64748b",fontSize:13,marginTop:8,marginLeft:4}}>
            {filtered.length} result{filtered.length !== 1 ? "s" : ""} found
          </p>
        )}
      </div>

      {filtered.length === 0 ? (
        <div style={{textAlign:"center",padding:"40px 20px",color:"#475569",fontSize:15}}>
          No domain found for <strong style={{color:"#fff"}}>"{query}"</strong>
          <p style={{fontSize:13,marginTop:8}}>Try: devops, fullstack, AI, cyber, mobile</p>
        </div>
      ) : (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
          {filtered.map((d,i) => (
            <button key={d.id} onClick={() => onPick(d)}
              style={{background:"#1e293b",border:"2px solid "+colors[i%colors.length]+"55",borderRadius:16,padding:"28px 16px",cursor:"pointer",textAlign:"center",color:"#fff",width:"100%",transition:"all 0.2s"}}
              onMouseOver={e => {e.currentTarget.style.transform="scale(1.03)"; e.currentTarget.style.borderColor=colors[i%colors.length];}}
              onMouseOut={e => {e.currentTarget.style.transform="scale(1)"; e.currentTarget.style.borderColor=colors[i%colors.length]+"55";}}>
              <div style={{fontSize:44,marginBottom:10}}>{d.emoji}</div>
              <div style={{fontWeight:700,fontSize:15,color:"#f1f5f9"}}>{d.label}</div>
            </button>
          ))}
        </div>
      )}

      {!query && (
        <p style={{textAlign:"center",color:"#475569",fontSize:13,marginTop:20}}>
          Or scroll and click any domain above
        </p>
      )}
    </div>
  );
}
